### Browser Inference with Web Workers using Transformers.js

Source: https://context7.com/huggingface/transformers.js/llms.txt

This snippet demonstrates how to use Web Workers for model inference in a browser environment. It prevents the main thread from being blocked during potentially long-running operations like model loading and inference. The code utilizes a singleton pattern for efficient model loading and communication between the main thread and the worker via messages.

```javascript
// worker.js
import { pipeline } from '@huggingface/transformers';

// Singleton pattern for model loading
class PipelineSingleton {
    static task = 'text-classification';
    static model = 'Xenova/distilbert-base-uncased-finetuned-sst-2-english';
    static instance = null;

    static async getInstance(progress_callback = null) {
        if (this.instance === null) {
            this.instance = await pipeline(this.task, this.model, {
                progress_callback
            });
        }
        return this.instance;
    }
}

// Listen for messages from main thread
self.addEventListener('message', async (event) => {
    const { type, data } = event.data;

    if (type === 'classify') {
        // Get or create classifier
        const classifier = await PipelineSingleton.getInstance((x) => {
            // Send download progress to main thread
            self.postMessage({ type: 'download', data: x });
        });

        // Run classification
        const result = await classifier(data.text);

        // Send result back to main thread
        self.postMessage({ type: 'result', data: result });
    }
});

```

```javascript
// main.js
// Create worker
const worker = new Worker(new URL('./worker.js', import.meta.url), {
    type: 'module'
});

// Listen for messages from worker
worker.addEventListener('message', (event) => {
    const { type, data } = event.data;

    if (type === 'download') {
        console.log('Download progress:', data);
    } else if (type === 'result') {
        console.log('Classification result:', data);
        // Update UI with result
    }
});

// Send classification request to worker
function classify(text) {
    worker.postMessage({
        type: 'classify',
        data: { text }
    });
}

// Usageclassify('I love this product!');

